void adaptive_sort(std::vector<int>& arr) {
    int n = arr.size();
    if (n < 2) return;
    bool s = 1, r = 1;
    for (int i = 1; i < n && (s || r); ++i) {
        if (arr[i] < arr[i-1]) s = 0;
        if (arr[i] > arr[i-1]) r = 0;
    }
    if (s) return;
    if (r) {
        for (int i = 0; i < n / 2; ++i) std::swap(arr[i], arr[n - 1 - i]);
        return;
    }
    quicksort(arr, 0, n - 1);
}

void quicksort(std::vector<int>& arr, int low, int high) {
    while (low < high) {
        if (high - low < 20) {
            for (int i = low + 1; i <= high; ++i) {
                int k = arr[i], j = i - 1;
                while (j >= low && arr[j] > k) { arr[j+1] = arr[j]; j--; }
                arr[j+1] = k;
            }
            break;
        }
        int p = partition(arr, low, high);
        if (p - low < high - p) {
            quicksort(arr, low, p - 1);
            low = p + 1;
        } else {
            quicksort(arr, p + 1, high);
            high = p - 1;
        }
    }
}

int partition(std::vector<int>& arr, int low, int high) {
    int mid = low + (high - low) / 2;
    if (arr[mid] < arr[low]) std::swap(arr[low], arr[mid]);
    if (arr[high] < arr[low]) std::swap(arr[low], arr[high]);
    if (arr[high] < arr[mid]) std::swap(arr[mid], arr[high]);
    std::swap(arr[mid], arr[high]);
    int v = arr[high], i = low;
    for (int j = low; j < high; ++j) if (arr[j] <= v) std::swap(arr[i++], arr[j]);
    std::swap(arr[i], arr[high]);
    return i;
}

